/**
 * ProductCard.jsx
 *
 * Displays a single product with its emoji, badge, name, model,
 * description, price, and a WhatsApp order button.
 *
 * Props:
 *   product - Product object from src/data/products.js
 */

import { waLink, BADGE_COLORS } from '../../utils/constants';

const ProductCard = ({ product }) => {
  const { name, model, price, badge, description, emoji, category } = product;

  // Build pre-filled WhatsApp message for this specific product
  const orderMessage = `Hi! I'm interested in the ${name} (${model}) — ${price}. Is it available?`;

  return (
    <article className="card card-hover flex flex-col overflow-hidden">

      {/* ── Emoji thumbnail area ─────────────────────────────────── */}
      <div className="relative bg-light-raised dark:bg-dark-raised h-40 flex items-center justify-center">
        <span className="text-6xl" role="img" aria-label={category}>
          {emoji}
        </span>

        {/* Badge — only shown if product has one */}
        {badge && (
          <span
            className={`badge absolute top-3 left-3 ${BADGE_COLORS[badge] || 'bg-brand-green'}`}
          >
            {badge}
          </span>
        )}
      </div>

      {/* ── Card body ────────────────────────────────────────────── */}
      <div className="p-5 flex flex-col flex-1 gap-2">
        <h3 className="font-semibold text-[15px] text-dark-bg dark:text-white">
          {name}
        </h3>

        <p className="font-mono text-[11px] tracking-wide text-dark-border2 dark:text-white/30">
          {model}
        </p>

        <p className="text-[13px] font-light text-dark-raised dark:text-white/50 leading-relaxed flex-1">
          {description}
        </p>

        {/* ── Price + CTA ──────────────────────────────────────────── */}
        <div className="flex items-center justify-between mt-4 pt-4 border-t border-light-border dark:border-dark-border">
          <span className="font-display text-[22px] text-brand-green">
            {price}
          </span>

          <a
            href={waLink(orderMessage)}
            target="_blank"
            rel="noreferrer"
            className="
              text-brand-green border border-brand-green bg-brand-green-10
              text-[13px] font-semibold px-3 py-2 rounded-md
              transition-all duration-200 hover:bg-brand-green hover:text-white
            "
          >
            Order →
          </a>
        </div>
      </div>
    </article>
  );
};

export default ProductCard;
